'use client';

interface AnswerButtonProps {
  label: 'a' | 's' | 'd' | 'f';
  text: string;
  onClick: () => void;
  disabled?: boolean;
  color?: string;
}

const getLabelColor = (label: 'a' | 's' | 'd' | 'f') => {
  switch (label) {
    case 'a': return 'text-red-400';
    case 's': return 'text-green-400';
    case 'd': return 'text-cyan-400';
    case 'f': return 'text-yellow-400';
  }
};

const getCircle = (label: 'a' | 's' | 'd' | 'f') => {
  const map = { a: '◯', s: '●', d: '◉', f: '◎' };
  return map[label];
};

export default function AnswerButton({
  label,
  text,
  onClick,
  disabled = false,
  color = 'text-green-300',
}: AnswerButtonProps) {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      className={`w-full px-3 py-2 text-left transition font-mono bg-black hover:bg-white hover:bg-opacity-10 ${disabled ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}`}
    >
      <span className={`inline-block w-3 font-bold ${getLabelColor(label)}`}>
        {getCircle(label)}
      </span>
      <span className={`${color} ml-2 font-bold`}>{label.toUpperCase()}</span>
      <span className={`${color} ml-3`}>{text}</span>
    </button>
  );
}
