'use client';

/**
 * Componente: QuestionDisplay
 * Muestra una pregunta con sus 4 opciones (a, s, d, f)
 */

import { Pregunta } from '@/lib/types';
import AnswerButton from './AnswerButton';

interface QuestionDisplayProps {
  question: Pregunta;
  progress: {
    current: number;
    total: number;
  };
  onAnswer: (answer: 'a' | 's' | 'd' | 'f') => void;
  isLoading: boolean;
}

export default function QuestionDisplay({
  question,
  progress,
  onAnswer,
  isLoading,
}: QuestionDisplayProps) {
  const getDifficultyColor = (difficulty: number) => {
    switch (difficulty) {
      case 1:
        return 'bg-green-100 text-green-800';
      case 2:
        return 'bg-yellow-100 text-yellow-800';
      case 3:
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getDifficultyLabel = (difficulty: number) => {
    switch (difficulty) {
      case 1:
        return 'BAJA';
      case 2:
        return 'MEDIA';
      case 3:
        return 'ALTA';
      default:
        return 'DESCONOCIDA';
    }
  };

  return (
    <div className="min-h-screen bg-black p-4 font-mono text-sm text-green-300">
      <div className="max-w-3xl mx-auto">
        {/* Encabezado */}
        <div className="flex justify-between items-center mb-3 pb-1 border-b border-green-300">
          <div className="flex items-center gap-3">
            <div>Q{progress.current.toString().padStart(2, '0')}/{progress.total}</div>
            <div className="text-xs text-yellow-600">{getDifficultyLabel(question.difficulty)}</div>
          </div>
          <div>{Math.round((progress.current / progress.total) * 100)}%</div>
        </div>

        {/* Barra de progreso */}
        <div className="mb-3 text-xs">
          [{"=".repeat(Math.round((progress.current / progress.total) * 20))}{"─".repeat(20 - Math.round((progress.current / progress.total) * 20))}]
        </div>

        {/* Pregunta */}
        <div className="mb-4">
          <div className="mb-4 leading-relaxed whitespace-pre-wrap">
            {question.text}
          </div>

          {/* Opciones */}
          <div className="space-y-1 mb-4">
            <AnswerButton
              label="a"
              text={question.options.a}
              onClick={() => onAnswer('a')}
              disabled={isLoading}
            />
            <AnswerButton
              label="s"
              text={question.options.s}
              onClick={() => onAnswer('s')}
              disabled={isLoading}
            />
            <AnswerButton
              label="d"
              text={question.options.d}
              onClick={() => onAnswer('d')}
              disabled={isLoading}
            />
            <AnswerButton
              label="f"
              text={question.options.f}
              onClick={() => onAnswer('f')}
              disabled={isLoading}
            />
          </div>

          {isLoading && (
            <div className="text-yellow-600">$ verificando respuesta...</div>
          )}
        </div>

        {/* Footer */}
        <div className="text-xs border-t border-green-300 pt-2 text-green-500">
          A | S | D | F   ← | →   ESC
        </div>
      </div>
    </div>
  );
}
